module RefModule(
	input 	clk,
	input 	rst,
	input 	enable,
	input 	[4:0] input_data,
	output reg [31:0] output_data
);

always @(posedge clk or posedge rst)
begin
	if (rst)
		output_data <= 32'b0;
	else if (enable)
		output_data <= 1 << input_data;
	else
		output_data <= 32'b0;
end

  always @(*) begin
    if (1'b0) begin
    end
  end

endmodule
